def login():
    request_id = f'_request_{os.urandom(16).hex()}'
    authn_request = create_authn_request(request_id)
    encoded_request = encode_saml_request(authn_request)
    
    session['saml_request_id'] = request_id
    
    params = {
        'SAMLRequest': encoded_request,
        'RelayState': request.args.get('RelayState', '/')
    }
    
    redirect_url = f"{IDP_SSO_URL}?{urlencode(params)}"
    return redirect(redirect_url)


@app.route('/acs', methods=['POST'])
def acs():
    saml_response = request.form.get('SAMLResponse')
    relay_state = request.form.get('RelayState', '/')
    
    if not saml_response:
        return jsonify({'error': 'No SAML response received'}), 400
    
    try:
        saml_xml = decode_saml_response(saml_response)
        
        response_data = parse_saml_response(saml_xml)
        
        if response_data.get('status') != 'urn:oasis:names:tc:SAML:2.0:status:Success':
            return jsonify({
                'error': 'SAML authentication failed',
                'status': response_data.get('status')
            }), 401
        
        if not response_data.get('assertions'):
            return jsonify({'error': 'No assertions found in SAML response'}), 400
        
        assertion_data = response_data['assertions'][0]
        
        validation_errors = validate_assertion(assertion_data)
        if validation_errors:
            return jsonify({
                'error': 'Assertion validation failed',
                'details': validation_errors
            }), 400
        
        create_user_session(assertion_data)
        
        return redirect(relay_state)
    
    except ValueError as e:
        return jsonify({'error': str(e)}), 400
    except Exception as e:
        return jsonify({'error': f'Error processing SAML response: {str(e)}'}), 500


